import json,re,collections
d=json.load(open('data/cp4_corpus_s3gear_329.corrected.json'))
ev=d['evidence']
print('n evidence', len(ev))
print('keys', list(ev[0]))
sectors={'manufactur':0,'healthcare':0,'health care':0,'retail':0,'financ':0,'bank':0,'transport':0,'logistic':0,'construction':0,'agricultur':0,'education':0,'legal':0,'customer service':0,'software':0,'call cent':0,'insurance':0,'hospitality':0,'mining':0,'energy':0}
def full(e):
    return ' '.join(str(e.get(k,'')) for k in e).lower()
rows_with=0
for e in ev:
    t=full(e)
    hit=False
    for s in sectors:
        if s in t:
            sectors[s]+=1; hit=True
    if hit: rows_with+=1
print('rows mentioning any sector token:', rows_with, '/', len(ev))
for k,v in sorted(sectors.items(), key=lambda x:-x[1]): print(f'  {k:18s} {v}')
EOF

